  `session_id` bigint NOT NULL,
  PRIMARY KEY (`id`),
  KEY `chatbot_messages_session_id_429ee8c3_fk_chatbot_sessions_id` (`session_id`),
  CONSTRAINT `chatbot_messages_session_id_429ee8c3_fk_chatbot_sessions_id` FOREIGN KEY (`session_id`) REFERENCES `chatbot_sessions` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=3217 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
