INSERT INTO `chatbot_messages` VALUES (2964,'BOT','Rất tiếc, mình không tìm thấy món ăn cụ thể nào ở Thủ Dầu Một, Bình Dương. Bạn có muốn mình tìm nhà hàng ở khu vực này không? Hoặc bạn có thể cho mình biết bạn muốn ăn món gì (ví dụ: lẩu, nướng, món Việt, món Hàn) để mình tìm kiếm dễ hơn nhé.',NULL,'{}','SHOW_INFO','{}','2026-04-21 07:49:58.602079',279),(2965,'USER','món ăn ở thủ dầu một',NULL,'{}',NULL,'{}','2026-04-21 07:51:03.559527',279),(2966,'BOT','Ở Thủ Dầu Một, Bình Dương, bạn có thể tham khảo một số món ăn sau:\n\n*   **Naan Garlic** (Bánh nướng tỏi) tại nhà hàng Namaste India - 40.000đ\n*   **Samosa** (Bánh gối Ấn) tại nhà hàng Namaste India - 50.000đ\n*   **Lassi Mango** (Sữa chua xoài) tại nhà hàng Namaste India - 60.000đ\n*   **Biryani** (Cơm nị) tại nhà hàng Namaste India - 120.000đ\n*   **Chicken Tikka Masala** (Cà ri gà) tại nhà hàng Namaste India - 150.000đ\n*   **Nước Ép Cần Tây** (Detox cơ thể) tại nhà hàng Salad Stop! - 60.000đ\n\nBạn có muốn mình tìm nhà hàng cụ thể nào không?\n',NULL,'{}','SHOW_DISHES','{\"dishes\": [{\"id\": 79, \"name\": \"Naan Garlic\", \"price\": 40000.0, \"category\": \"Bánh\", \"image_url\": null, \"restaurant\": {\"id\": 18, \"name\": \"Namaste India\"}, \"description\": \"Bánh nướng tỏi\"}, {\"id\": 81, \"name\": \"Samosa\", \"price\": 50000.0, \"category\": \"Khai vị\", \"image_url\": null, \"restaurant\": {\"id\": 18, \"name\": \"Namaste India\"}, \"description\": \"Bánh gối Ấn\"}, {\"id\": 82, \"name\": \"Lassi Mango\", \"price\": 60000.0, \"category\": \"Đồ uống\", \"image_url\": null, \"restaurant\": {\"id\": 18, \"name\": \"Namaste India\"}, \"description\": \"Sữa chua xoài\"}, {\"id\": 80, \"name\": \"Biryani\", \"price\": 120000.0, \"category\": \"Cơm\", \"image_url\": null, \"restaurant\": {\"id\": 18, \"name\": \"Namaste India\"}, \"description\": \"Cơm nị\"}, {\"id\": 78, \"name\": \"Chicken Tikka Masala\", \"price\": 150000.0, \"category\": \"Curry\", \"image_url\": null, \"restaurant\": {\"id\": 18, \"name\": \"Namaste India\"}, \"description\": \"Cà ri gà\"}, {\"id\": 61, \"name\": \"Nước Ép Cần Tây\", \"price\": 60000.0, \"category\": \"Đồ uống\", \"image_url\": null, \"restaurant\": {\"id\": 14, \"name\": \"Salad Stop!\"}, \"description\": \"Detox cơ thể\"}], \"filters\": {\"dish\": \"\", \"cuisine\": \"\", \"location\": \"Thủ Dầu Một\", \"restaurant\": \"\"}}','2026-04-21 07:51:08.247252',279),(2967,'USER','hi',NULL,'{}',NULL,'{}','2026-04-21 07:58:10.289981',280),(2968,'BOT','Chào bạn, mình là trợ lý đặt bàn nhà hàng TableBookingAI. Mình có thể giúp gì cho bạn hôm nay? Bạn muốn tìm nhà hàng, xem thực đơn hay đặt bàn không?',NULL,'{}','SHOW_INFO','{}','2026-04-21 07:58:11.907192',280),(2969,'USER','gợi ý vài món ở thủ dầu một, quận 1 hcm đi',NULL,'{}',NULL,'{}','2026-04-21 07:58:52.690600',280),(2970,'BOT','Ở Thủ Dầu Một, bạn có thể thử các món Ấn Độ tại nhà hàng Namaste India như Naan Garlic (40,000đ), Samosa (50,000đ), Lassi Mango (60,000đ), Biryani (120,000đ) và Chicken Tikka Masala (150,000đ). Ngoài ra còn có Nước Ép Cần Tây (60,000đ) tại Salad Stop!.\n\nRất tiếc, mình không tìm thấy món ăn nào ở Quận 1 TP. Hồ Chí Minh. Bạn có muốn mình tìm nhà hàng ở Quận 1 không?',NULL,'{}','SHOW_INFO','{}','2026-04-21 07:58:56.759702',280),(2971,'USER','gợi ý món ở hcm',NULL,'{}',NULL,'{}','2026-04-21 08:02:44.281122',280),(2972,'BOT','Rất tiếc, mình không tìm thấy món ăn cụ thể nào ở TP. Hồ Chí Minh. Bạn có muốn mình tìm món ăn theo loại hình ẩm thực (ví dụ: món chay, món Hàn, món lẩu) hay theo tên nhà hàng không?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:02:50.935418',280),(2973,'USER','gợi ý vài món ở thủ dầu một, quận 1 hcm đi',NULL,'{}',NULL,'{}','2026-04-21 08:30:27.778433',280),(2974,'BOT','Ở Thủ Dầu Một, bạn có thể tham khảo các món sau:\n*   **Naan Garlic** (Namaste India) | Giá: 40,000đ | Loại: Bánh\n*   **Samosa** (Namaste India) | Giá: 50,000đ | Loại: Khai vị\n*   **Lassi Mango** (Namaste India) | Giá: 60,000đ | Loại: Đồ uống\n*   **Biryani** (Namaste India) | Giá: 120,000đ | Loại: Cơm\n*   **Chicken Tikka Masala** (Namaste India) | Giá: 150,000đ | Loại: Curry\n*   **Nước Ép Cần Tây** (Salad Stop!) | Giá: 60,000đ | Loại: Đồ uống\n\nRất tiếc, mình không tìm thấy món ăn nào ở Quận 1 TP.HCM. Bạn có muốn mình tìm nhà hàng ở Quận 1 không?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:30:32.911168',280),(2975,'USER','gợi ý vài món ở thủ dầu một, quận 1 hcm đi',NULL,'{}',NULL,'{}','2026-04-21 08:31:12.314014',280),(2976,'BOT','aa Xin lỗi bạn, mình gặp sự cố kỹ thuật. Bạn thử lại sau nhé ?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:31:48.892437',280),(2977,'USER','gợi ý vài món ở thủ dầu một, quận 1 hcm đi',NULL,'{}',NULL,'{}','2026-04-21 08:33:52.926153',280),(2978,'BOT','Dạ, bạn muốn tìm món ăn hay nhà hàng ạ? Và bạn thích ăn món Việt, món Á hay món Âu?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:33:54.627403',280),(2979,'USER','gợi ý đại đi',NULL,'{}',NULL,'{}','2026-04-21 08:35:56.552671',280),(2980,'BOT','Dạ, bạn muốn tìm món ăn hay nhà hàng ạ? Và bạn thích ăn món Việt, món Á hay món Âu?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:35:58.052122',280),(2981,'USER','gợi ý nhà hàng',NULL,'{}',NULL,'{}','2026-04-21 08:36:09.707605',280),(2982,'BOT','Dạ, bạn muốn tìm nhà hàng ở khu vực nào ạ? Ví dụ: \"Thủ Dầu Một\", \"Quận 1, TP.HCM\", hay \"Bình Thạnh, TP.HCM\"?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:36:11.003305',280),(2983,'USER','tôi ở bình dương. gợi ý vài nhà hàng đi',NULL,'{}',NULL,'{}','2026-04-21 08:36:55.067198',280),(2984,'BOT','Dạ, bạn muốn tìm nhà hàng ở khu vực nào tại Bình Dương ạ? Ví dụ: \"Thành phố Thủ Dầu Một\", \"Thành phố Dĩ An\", hay \"Thành phố Thuận An\"?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:36:56.453660',280),(2985,'USER','ở thủ dầu một',NULL,'{}',NULL,'{}','2026-04-21 08:37:09.485197',280),(2986,'BOT','Dạ, bạn muốn tìm nhà hàng với mức giá như thế nào ạ (bình dân, trung bình, hay cao cấp)? Và bạn thích thưởng thức ẩm thực theo phong cách nào (ví dụ: món Việt, món Á, món Âu, lẩu, nướng,...)?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:37:10.835647',280),(2987,'USER','bình dân thôi, gợi ý đại món gì cũng được',NULL,'{}',NULL,'{}','2026-04-21 08:37:46.963173',280),(2988,'BOT','Dạ, mình xin gợi ý một số nhà hàng bình dân tại Thủ Dầu Một có các món ăn đa dạng ạ:\n\n*   **Nhà hàng Lẩu Bò Tơ Năm Sánh**: Chuyên về lẩu bò tươi ngon, giá cả phải chăng.\n*   **Quán Cơm Niêu Gia Đình**: Phục vụ các món cơm niêu đậm đà hương vị Việt Nam.\n*   **Bánh Xèo Miền Tây 79**: Thưởng thức bánh xèo giòn rụm với nhiều loại nhân hấp dẫn.\n\nBạn có muốn mình tìm thêm thông tin về nhà hàng nào trong số này không ạ? Hoặc bạn có muốn tìm món cụ thể nào không?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:37:48.899150',280),(2989,'USER','cho tôi link và địa chỉ nhà hàng đầu tiên',NULL,'{}',NULL,'{}','2026-04-21 08:38:47.764206',280),(2990,'BOT','Dạ, Nhà hàng Lẩu Bò Tơ Năm Sánh có địa chỉ tại 368 Nguyễn Thị Minh Khai, Phường Phú Hòa, Thành phố Thủ Dầu Một, Bình Dương.\n\nHiện tại mình chưa có chức năng cung cấp link trực tiếp ạ. Bạn có thể tìm kiếm tên nhà hàng trên Google Maps để xem thêm thông tin chi tiết và chỉ đường nhé.\n\nBạn có muốn đặt bàn tại đây không ạ?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:38:49.768478',280),(2991,'USER','chi tiết nhà hàng này',NULL,'{}',NULL,'{}','2026-04-21 08:40:34.657403',280),(2992,'BOT','Rất tiếc, mình không tìm thấy thông tin chi tiết về nhà hàng \"Lẩu Bò Tơ Năm Sánh\" trong hệ thống ạ. Có lẽ tên nhà hàng có chút khác biệt hoặc nhà hàng chưa được cập nhật thông tin.\n\nBạn có muốn mình thử tìm kiếm lại với một tên khác hoặc tìm một nhà hàng tương tự không ạ?',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:40:37.694133',280),(2993,'USER','gợi ý nhà hàng ở tphcm',NULL,'{}',NULL,'{}','2026-04-21 08:43:11.715767',281),(2994,'BOT','Chào bạn! Rất vui được hỗ trợ bạn tìm nhà hàng tại TP.HCM.\n\nĐể mình có thể gợi ý những địa điểm phù hợp nhất với sở thích của bạn, bạn vui lòng cho mình biết thêm một chút thông tin nhé:\n1. Bạn đang muốn thưởng thức **loại hình ẩm thực** nào (Ví dụ: món Nhật, món Hàn, lẩu, hải sản, món Việt...)?\n2. **Mức giá** bạn mong muốn là khoảng bao nhiêu (Bình dân, trung bình hay cao cấp)?\n3. Bạn muốn tìm nhà hàng ở **quận/khu vực cụ thể** nào tại TP.HCM không?\n\nBạn cứ chia sẻ nhé, mình sẽ tìm ngay giúp bạn!',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:43:27.245640',281),(2995,'USER','làm tí hải sản, giá khoảng 100-200k.',NULL,'{}',NULL,'{}','2026-04-21 08:53:04.152546',281),(2996,'BOT','Rất tiếc, với mức giá 100.000đ - 200.000đ cho các nhà hàng hải sản tại TP.HCM, hiện tại mình chưa tìm thấy lựa chọn phù hợp trong hệ thống. Các nhà hàng hải sản thường có mức giá trung bình đến cao cấp hơn một chút.\n\nBạn có muốn mình thử tìm kiếm với các tiêu chí khác không? Ví dụ:\n- Mở rộng mức giá lên \"Trung bình\" (Medium)?\n- Tìm các món ăn cụ thể khác (không phải hải sản) trong tầm giá 100-200k?\n- Hoặc bạn có thể cho mình biết khu vực cụ thể (quận) mà bạn muốn tìm, biết đâu mình sẽ tìm được quán ăn bình dân phù hợp hơn!',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:53:35.474414',281),(2997,'USER','thôi gợi ý đại đi tôi chưa biết chọn gì',NULL,'{}',NULL,'{}','2026-04-21 08:54:09.808064',281),(2998,'BOT','Để mình gợi ý cho bạn một vài lựa chọn phổ biến và được yêu thích tại TP.HCM nhé. Vì hải sản thường có mức giá khá cao, mình sẽ gợi ý một số nhà hàng có phong cách đa dạng, bạn xem thử có ưng ý không:\n\n1. **Nhà hàng Lẩu Cua Đất Mũi**: Nổi tiếng với các món về cua, không gian rộng rãi, rất hợp để đi ăn cùng bạn bè hoặc gia đình.\n2. **Nhà hàng Hải Sản Biển Đông**: Một chuỗi nhà hàng hải sản khá quen thuộc, có nhiều chi nhánh tại các quận, hải sản tươi sống và thực đơn phong phú.\n3. **Nhà hàng Ẩm Thực Quê Nhà**: Nếu bạn muốn thưởng thức hải sản kết hợp với các món ăn mang hương vị truyền thống Việt Nam trong không gian sang trọng hơn một chút.\n\nBạn có muốn mình kiểm tra thông tin chi tiết (địa chỉ, giờ mở cửa) của nhà hàng nào trong số này không? Hoặc nếu bạn muốn đổi sang món khác như **món Nhật, món Hàn hay món Việt** thì cứ bảo mình nhé!',NULL,'{}','SHOW_INFO','{}','2026-04-21 08:54:44.779373',281),(2999,'USER','tôi muốn ăn hải sản',NULL,'{}',NULL,'{}','2026-04-21 09:20:52.570450',282),(3000,'BOT','Chào bạn! Rất sẵn lòng hỗ trợ bạn tìm một nhà hàng hải sản ngon.\n\nĐể mình có thể gợi ý địa điểm phù hợp nhất, bạn vui lòng cho mình biết thêm một vài thông tin nhé:\n1. Bạn muốn ăn hải sản ở **khu vực nào** (quận, huyện hoặc thành phố)?\n2. Bạn mong muốn mức giá như thế nào (bình dân, trung bình hay cao cấp)?\n\nMình chờ thông tin từ bạn!',NULL,'{}','SHOW_INFO','{}','2026-04-21 09:21:04.052622',282),(3001,'USER','ở quận 1, giá cả khoảng 200k',NULL,'{}',NULL,'{}','2026-04-21 09:21:39.282021',282),(3002,'BOT','Rất tiếc, hiện tại mình không tìm thấy nhà hàng hải sản nào tại Quận 1 trong hệ thống với mức giá bình dân (khoảng 200k).\n\nTại Quận 1, mình có một số nhà hàng khác như **Món Việt House 33** (chuyên món Việt) hoặc **Sync Test Restaurant** (chuyên món Nhật) với mức giá khá hợp lý.\n\nBạn có muốn mình tìm kiếm lại ở các quận lân cận hoặc thử đổi sang loại hình ẩm thực khác không?',NULL,'{}','SHOW_RESTAURANTS','{\"filters\": {\"price\": \"\", \"cuisine\": \"\", \"location\": \"Quận 1\"}, \"restaurants\": [{\"id\": 132, \"name\": \"Hàn Quốc Corner 97\", \"phone\": \"0244927955\", \"rating\": 5.0, \"address\": \"613 Phố Huế, Quận Ba Đình, Thành phố Hà Nội\", \"image_url\": null, \"description\": \"Không gian thưởng thức Hàn Quốc tuyệt vời tại Hà Nội.\", \"price_label\": \"Vừa phải\", \"price_range\": \"50000\", \"cuisine_type\": \"Hàn Quốc\", \"opening_hours\": \"09:00 - 22:00\"}, {\"id\": 68, \"name\": \"Món Việt House 33\", \"phone\": \"0245339240\", \"rating\": 5.0, \"address\": \"817 Đường Lê Lợi, Quận 1, Thành phố Hồ Chí Minh\", \"image_url\": null, \"description\": \"Không gian thưởng thức Món Việt tuyệt vời tại TP. Hồ Chí Minh.\", \"price_label\": \"Vừa phải\", \"price_range\": \"200000\", \"cuisine_type\": \"Món Việt\", \"opening_hours\": \"09:00 - 22:00\"}, {\"id\"