INSERT INTO `collections` VALUES (7,'Buffet Ngập Tràn','Thỏa sức thưởng thức hàng trăm món ăn không giới hạn tại các nhà hàng buffet nổi tiếng.','https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=800',1,'2026-05-04 11:15:55.486856','Hot','collections/collection_7.jpg'),(8,'Lẩu & Nướng Hấp Dẫn','Tụ tập bạn bè bên nồi lẩu nghi ngút khói hay những vỉ nướng xèo xèo thơm nức.','https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=800',1,'2026-05-04 11:15:55.488383','Yêu thích','collections/collection_8.jpg'),(9,'Nhà Hàng Sang Trọng','Không gian đẳng cấp, phục vụ chuyên nghiệp, dành cho các buổi tiệc quan trọng và tiếp khách.','https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=800',1,'2026-05-04 11:15:55.493473','Premium','collections/collection_9.jpg'),(10,'Ẩm Thực Nhật Bản','Trải nghiệm hương vị tinh tế của xứ sở hoa anh đào với sushi, sashimi và nướng Yakiniku.','https://images.unsplash.com/photo-1579871494447-9811cf80d66c?w=800',1,'2026-05-04 11:15:55.497441',NULL,'collections/collection_10.jpg'),(11,'Món Chay Thanh Tịnh','Những món ăn thuần chay tốt cho sức khỏe trong không gian yên bình.','https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=800',1,'2026-05-04 11:15:55.501244',NULL,'collections/collection_11.jpg'),(12,'Hải Sản Tươi Sống','Thưởng thức hải sản tươi ngon được chế biến đa dạng phong cách.','https://images.unsplash.com/photo-1519708227418-c8fd9a32b7a2?w=800',1,'2026-05-04 11:15:55.504956',NULL,'collections/collection_12.jpg'),(13,'Hẹn Hò Lãng Mạn','Không gian riêng tư, ấm cúng dành cho các cặp đôi trong những dịp đặc biệt.','https://images.unsplash.com/photo-1522673607200-16484837186f?w=800',1,'2026-05-04 11:15:55.508263','Lãng mạn','collections/romantic_dinner_premium.png');
