INSERT INTO `community_post` VALUES (1,'Khai trương chi nhánh mới tại Quận 1','khai-truong-chi-nhanh-moi-tai-quan-1','NEWS','Chúng tôi vui mừng thông báo về việc khai trương chi nhánh mới của nhà hàng Mộc Quán tại trung tâm Quận 1. Nhiều ưu đãi hấp dẫn đang chờ đón quý khách.','Mộc Quán khai trương chi nhánh mới với nhiều ưu đãi.','','PUBLISHED',0,0,'','','2026-05-04 13:33:31.729247','2026-05-04 13:33:31.729247',1),(2,'Tuyển dụng Nhân viên Phục vụ Part-time','tuyen-dung-nhan-vien-phuc-vu-part-time','RECRUITMENT','Nhà hàng cần tuyển 05 nhân viên phục vụ làm việc theo ca. Lương thưởng hấp dẫn, môi trường chuyên nghiệp.','Cần tuyển 05 nhân viên phục vụ tại Quận 3.','','PUBLISHED',0,0,'Hồ Chí Minh','25k - 30k/giờ','2026-05-04 14:02:14.679582','2026-05-04 14:02:14.679582',1),(3,'Tìm việc Phụ bếp tại Bình Dương','tim-viec-phu-bep-tai-binh-duong','SEEKING','Tôi có 2 năm kinh nghiệm làm phụ bếp Âu, cần tìm việc làm tại khu vực Thủ Dầu Một, Bình Dương.','Ứng viên tìm việc phụ bếp kinh nghiệm 2 năm.','','PUBLISHED',0,0,'Bình Dương','','2026-05-04 14:02:14.688818','2026-05-04 14:02:14.690060',1),(4,'Review: Buffet nướng chuẩn vị Hàn Quốc','review-buffet-nuong-chuan-vi-han-quoc','REVIEW','Trải nghiệm tuyệt vời tại quán nướng ABC. Thịt tươi, sốt đậm đà, không gian rộng rãi.','Một địa chỉ nướng không thể bỏ qua tại Hà Nội.','','PUBLISHED',0,0,'','','2026-05-04 14:02:14.696376','2026-05-04 14:02:14.696376',1),(5,'a','a','NEWS','aaaaa','aaaa','blog/thumbnails/post_1777905446.png','PUBLISHED',0,0,NULL,NULL,'2026-05-04 14:37:26.926544','2026-05-04 14:41:44.531715',2),(6,'aa','aa','NEWS','aa','','','PENDING',0,0,NULL,NULL,'2026-05-08 00:48:06.701117','2026-05-08 00:48:06.701117',40);
