--
-- Table structure for table `restaurants`
--

DROP TABLE IF EXISTS `restaurants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `restaurants` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `address` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `phone_number` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `description` longtext COLLATE utf8mb4_unicode_ci,
  `opening_hours` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rating` decimal(3,2) NOT NULL,
  `created_at` datetime(6) DEFAULT NULL,
  `updated_at` datetime(6) NOT NULL,
  `location_id` bigint DEFAULT NULL,
  `partner_id` bigint NOT NULL,
  `cuisine_type` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `price_range` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `latitude` decimal(12,9) DEFAULT NULL,
  `longitude` decimal(12,9) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `restaurants_partner_594242_idx` (`partner_id`),
  KEY `restaurants_locatio_7f8c42_idx` (`location_id`),
  KEY `restaurants_status_7a5ebb_idx` (`status`),
  KEY `restaurants_rating_93f534_idx` (`rating`),
  CONSTRAINT `restaurants_location_id_c8ed5633_fk_locations_id` FOREIGN KEY (`location_id`) REFERENCES `locations` (`id`),
  CONSTRAINT `restaurants_partner_id_d84ebde5_fk_partners_user_id` FOREIGN KEY (`partner_id`) REFERENCES `partners` (`user_id`)
) ENGINE=InnoDB AUTO_INCREMENT=246 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

