INSERT INTO `restaurants` VALUES (3,'Phở Thìn 1989','13 Lò Đúc','0241234567','Thương hiệu phở tái lăn nổi tiếng Hà Thành với nước dùng béo ngậy, thơm mùi gừng tỏi và thịt bò xào tái vừa tầm. Hương vị truyền thống từ năm 1989.','06:00 - 22:00','APPROVED',4.50,'2026-01-31 15:44:13.000000','2026-05-07 09:04:29.739820',8,4,'Món Việt','50000',21.030781600,105.854062600),(4,'Cơm Niêu Sài Gòn','27 Tú Xương','0281234567','Thưởng thức cơm niêu cháy cạnh giòn tan cùng các món ăn dân dã như cá kho tộ, canh chua. Không gian ấm cúng đậm chất truyền thống Việt Nam.','10:00 - 21:00','APPROVED',4.40,'2026-01-31 15:44:13.000000','2026-05-07 09:04:29.758888',4,4,'Món Việt','50000',10.778891400,106.686996700),(5,'Sushi Hokkaido Sachi','163 Phan Văn Trị','0289999999','Tinh hoa ẩm thực Nhật Bản với nguồn hải sản tươi sống nhập khẩu trực tiếp từ đảo Hokkaido. Không gian sang trọng, phục vụ chuyên nghiệp.','10:00 - 22:00','APPROVED',4.43,'2026-01-31 15:44:14.000000','2026-05-07 09:04:29.764157',6,5,'Nhật Bản','500000',10.798761500,106.720845900),(6,'GoGi House BBQ','TTTM Gigamall','0288888888','Quán nướng Hàn Quốc số 1 với những lát thịt bò Mỹ thượng hạng, nạc mỡ xen kẽ hoàn hảo. Trải nghiệm nướng tại bàn đúng điệu Seoul.','10:00 - 22:00','APPROVED',4.20,'2026-01-31 15:44:14.000000','2026-05-07 09:04:29.775101',7,5,'BBQ','200000',10.804349900,106.747260900),(7,'Pizza 4P\'s','8 Thủ Khoa Huân','0287777777','Pizza nướng lò củi kết hợp phong cách Nhật - Ý độc đáo. Nổi tiếng với phô mai Burrata tự làm và các dòng Pizza hải sản, hoa quả tươi.','11:00 - 23:00','APPROVED',4.25,'2026-01-31 15:44:14.000000','2026-05-07 09:04:29.782129',3,6,'Ý','200000',10.781808800,106.700619500),(8,'El Gaucho Steakhouse','74 Hai Bà Trưng','0286666666','Nhà hàng bít tết phong cách Argentina đẳng cấp với các loại thịt bò nhập khẩu chất lượng cao nhất, nướng trên than hồng giữ trọn vị ngọt.','16:00 - 23:00','APPROVED',4.67,'2026-01-31 15:44:14.000000','2026-05-07 09:04:29.787297',3,6,'Fine Dining','500000',10.7818088