DROP TABLE IF EXISTS `transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transactions` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `amount` decimal(12,2) NOT NULL,
  `transaction_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL,
  `payment_method` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `transaction_id` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` datetime(6) NOT NULL,
  `booking_id` bigint DEFAULT NULL,
  `wallet_id` bigint DEFAULT NULL,
  `note` longtext COLLATE utf8mb4_unicode_ci,
  `provider_create_date` varchar(14) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `provider_pay_date` varchar(14) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `provider_response_code` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `provider_transaction_no` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `transaction_id` (`transaction_id`),
  KEY `transactions_booking_id_00ee324e_fk_bookings_id` (`booking_id`),
  KEY `transactions_wallet_id_ce705075_fk_wallets_id` (`wallet_id`),
  CONSTRAINT `transactions_booking_id_00ee324e_fk_bookings_id` FOREIGN KEY (`booking_id`) REFERENCES `bookings` (`id`),
  CONSTRAINT `transactions_wallet_id_ce705075_fk_wallets_id` FOREIGN KEY (`wallet_id`) REFERENCES `wallets` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=56 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
